sys_script_fix.script:
// Fix Script will be called Tasker 2.8 - OU Abbreviation Update Tasker Number

// Enter OU Abbreviation
// this script will only update any tasks if an OU is provided on the line below.
// put the sys_id of the ou in the line below
var organizationalUnit = 'sys_id goes here';

// to update active and completed tasks, set the variable below to false
var activeOnly = true;

// The method called here in the Tasker Helpers script updates the Tasker Number OUs
// The function receives active only and runs for either all tasks or for all active only tasks
new TaskerHelpers().updateTaskerNumber(organizationalUnit, activeOnly);
